evaluators.evaluation_logic:
const checkpoints = [];

const programRegistrations = JSON.parse(localStorage.getItem('program_registrations') || '[]');
const programSessions = JSON.parse(localStorage.getItem('program_sessions') || '[]');
const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const seasons = JSON.parse(localStorage.getItem('seasons') || '[]');
const divisions = JSON.parse(localStorage.getItem('divisions') || '[]');
const players = JSON.parse(localStorage.getItem('players') || '[]');

// Helper: find Spring 2026 season and 12U division
const springSeason = seasons.find(s => s.year === 2026 && s.season_type === 'spring');
const div12 = divisions.find(d => d.code === '12u');

if (!springSeason || !div12) {
  return 0.0;
}

// Programs that are Spring 2026 + 12U
const eligibleProgramIds = programs
  .filter(p => p.season_id === springSeason.id && p.division_id === div12.id)
  .map(p => p.id);

// Candidate sessions: weekday, start_time >= '17:00', open
const candidateSessions = programSessions.filter(s => {
  if (!eligibleProgramIds.includes(s.program_id)) return false;
  if (!s.is_weekday) return false;
  if (!s.start_time || s.start_time < '17:00') return false;
  if (s.status !== 'open') return false;
  return true;
});

if (candidateSessions.length === 0) {
  return 0.0;
}

const minPrice = candidateSessions.reduce((min, s) => {
  const price = typeof s.price === 'number' ? s.price : Infinity;
  return price < min ? price : min;
}, Infinity);

// Helper: detect players created at runtime (id pattern 'player_1234')
const isGeneratedPlayerId = (id) => /^player_\d+$/.test(id || '');

// Registrations for generated players only (user-created)
const dynamicRegs = programRegistrations.filter(reg => isGeneratedPlayerId(reg.player_id));

// Qualifying registrations: for candidate sessions, pay_in_full, fully paid, confirmed
const qualifyingRegs = dynamicRegs.filter(reg => {
  const session = programSessions.find(s => s.id === reg.program_session_id);
  if (!session) return false;
  const program = programs.find(p => p.id === session.program_id);
  if (!program) return false;
  const seasonOk = program.season_id === springSeason.id;
  const divisionOk = program.division_id === div12.id;
  const weekdayOk = !!session.is_weekday;
  const timeOk = session.start_time && session.start_time >= '17:00';
  const openOk = session.status === 'open';
  if (!(seasonOk && divisionOk && weekdayOk && timeOk && openOk)) return false;

  const payFull = reg.payment_option === 'pay_in_full';
  const sessionPrice = typeof session.price === 'number' ? session.price : 0;
  const paidCorrect = reg.amount_due === 0 && reg.amount_paid === sessionPrice;
  const statusConfirmed = reg.status === 'confirmed';
  return payFull && paidCorrect && statusConfirmed;
});

// Among qualifying regs, which are on the cheapest candidate sessions?
const cheapestQualifyingRegs = qualifyingRegs.filter(reg => {
  const session = programSessions.find(s => s.id === reg.program_session_id);
  return session && typeof session.price === 'number' && session.price === minPrice;
});

// CP1 (0.5): User created at least one qualifying, fully paid registration on any matching Spring 2026 12U weekday evening session
checkpoints.push({ passed: qualifyingRegs.length > 0, weight: 0.5 });

// CP2 (0.5): At least one such registration is for the cheapest qualifying session
checkpoints.push({ passed: minPrice < Infinity && cheapestQualifyingRegs.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const savedGames = JSON.parse(localStorage.getItem('saved_games') || '[]');
const games = JSON.parse(localStorage.getItem('games') || '[]');
const teams = JSON.parse(localStorage.getItem('teams') || '[]');
const divisions = JSON.parse(localStorage.getItem('divisions') || '[]');

// Find 14U division and its Thunder team
const div14 = divisions.find(d => d.code === '14u');
let thunderTeam = null;
if (div14) {
  thunderTeam = teams.find(t => t.division_id === div14.id && /thunder/i.test(t.name || ''));
}
if (!thunderTeam) {
  return 0.0;
}

// All Thunder games from 2026-05-01 onward
const thunderGamesFromMay = games.filter(g => {
  const isThunder = g.home_team_id === thunderTeam.id || g.away_team_id === thunderTeam.id;
  if (!isThunder || !g.game_date) return false;
  const dateStr = g.game_date.slice(0, 10);
  return dateStr >= '2026-05-01';
});

// Sort by date+time ascending
thunderGamesFromMay.sort((a, b) => {
  const da = (a.game_date || '').slice(0, 10) + 'T' + (a.start_time || '00:00');
  const db = (b.game_date || '').slice(0, 10) + 'T' + (b.start_time || '00:00');
  if (da < db) return -1;
  if (da > db) return 1;
  return 0;
});

const nextThree = thunderGamesFromMay.slice(0, 3);
if (nextThree.length === 0) {
  return 0.0;
}

const targetIds = nextThree.map(g => g.id);
const savedGameIds = savedGames.map(sg => sg.game_id);

const savedCount = targetIds.filter(id => savedGameIds.includes(id)).length;

// CP1-3: number of correctly saved "next" games
checkpoints.push({ passed: savedCount >= 1, weight: 0.33 });
checkpoints.push({ passed: savedCount >= 2, weight: 0.33 });
checkpoints.push({ passed: savedCount >= 3, weight: 0.34 });

return checkmarks = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const shifts = JSON.parse(localStorage.getItem('volunteer_shifts') || '[]');
const signups = JSON.parse(localStorage.getItem('volunteer_signups') || '[]');
const fields = JSON.parse(localStorage.getItem('fields') || '[]');

const field2 = fields.find(f => f.name === 'Field 2');
if (!field2) {
  return 0.0;
}

const parseTimeToMinutes = (timeStr) => {
  if (!timeStr) return null;
  const match = timeStr.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (!match) return null;
  let h = parseInt(match[1], 10);
  const m = parseInt(match[2], 10);
  const ampm = match[3].toUpperCase();
  if (ampm === 'PM' && h !== 12) h += 12;
  if (ampm === 'AM' && h === 12) h = 0;
  return h * 60 + m;
};

// Qualifying June Field 2 concession shifts starting at or after 5:00 PM
const qualifyingShifts = shifts.filter(s => {
  if (s.field_id !== field2.id) return false;
  if (s.role !== 'concession_stand') return false;
  if (!s.date) return false;
  const ym = s.date.slice(0, 7);
  if (ym !== '2026-06') return false;
  const startMin = parseTimeToMinutes(s.start_time);
  if (startMin == null || startMin < 17 * 60) return false;
  return true;
});

if (qualifyingShifts.length === 0) {
  return 0.0;
}

qualifyingShifts.sort((a, b) => {
  const da = (a.date || '').slice(0, 10);
  const db = (b.date || '').slice(0, 10);
  if (da < db) return -1;
  if (da > db) return 1;
  const ta = parseTimeToMinutes(a.start_time) || 0;
  const tb = parseTimeToMinutes(b.start_time) || 0;
  return ta - tb;
});

const earliestTwo = qualifyingShifts.slice(0, 2);
if (earliestTwo.length === 0) {
  return 0.0;
}
const earliestTwoIds = earliestTwo.map(s => s.id);

// New (runtime) signups have ids generated as 'vol_signup_###'
const dynamicSignups = signups.filter(s => /^vol_signup_\d+/.test(s.id || '') && s.status === 'confirmed');

const signedCount = earliestTwoIds.filter(id => dynamicSignups.some(s => s.volunteer_shift_id === id)).length;

checkpoints.push({ passed: signedCount >= 1, weight: 0.5 });
checkpoints.push({ passed: signedCount >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('order_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

// Identify qualifying products dynamically
const youthTeeIds = products
  .filter(p => p.product_type === 'youth_t_shirt'
    && p.is_youth
    && typeof p.price === 'number' && p.price < 20
    && Array.isArray(p.available_sizes) && p.available_sizes.includes('youth_m'))
  .map(p => p.id);

const adultHatIds = products
  .filter(p => p.product_type === 'hat'
    && p.is_adult
    && typeof p.price === 'number' && p.price < 25)
  .map(p => p.id);

const waterBottleIds = products
  .filter(p => p.product_type === 'water_bottle'
    && typeof p.rating === 'number' && p.rating >= 4.0)
  .map(p => p.id);

if (orders.length === 0) {
  return 0.0;
}

let hasYouthTee = false;
let hasAdultHat = false;
let hasRatedBottle = false;

const standardOrders = orders.filter(o => o.shipping_method === 'standard');

for (const order of standardOrders) {
  const items = orderItems.filter(oi => oi.order_id === order.id);
  for (const item of items) {
    if (item.quantity >= 1) {
      if (youthTeeIds.includes(item.product_id) && item.selected_size === 'youth_m') {
        hasYouthTee = true;
      }
      if (adultHatIds.includes(item.product_id)) {
        hasAdultHat = true;
      }
      if (waterBottleIds.includes(item.product_id)) {
        hasRatedBottle = true;
      }
    }
  }
}

// CP1 (0.34): Youth medium T-shirt under $20 purchased in a Standard-shipping order
checkpoints.push({ passed: hasYouthTee, weight: 0.34 });

// CP2 (0.33): Adult hat under $25 purchased in a Standard-shipping order
checkpoints.push({ passed: hasAdultHat, weight: 0.33 });

// CP3 (0.33): Water bottle rated >= 4.0 purchased in a Standard-shipping order
checkpoints.push({ passed: hasRatedBottle, weight: 0.33 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const clinics = JSON.parse(localStorage.getItem('clinics') || '[]');
const regs = JSON.parse(localStorage.getItem('clinic_registrations') || '[]');

// Candidate July 2026 pitching clinics with price <= 120
const candidateClinics = clinics.filter(c => {
  if (c.skill_focus !== 'pitching') return false;
  if (typeof c.price !== 'number' || c.price > 120) return false;
  if (!c.start_date) return false;
  const ym = c.start_date.slice(0, 7);
  return ym === '2026-07';
});

if (candidateClinics.length === 0) {
  return 0.0;
}

// Determine best clinic(s): max hours, then lowest price among those
let maxHours = 0;
for (const c of candidateClinics) {
  const h = typeof c.total_training_hours === 'number' ? c.total_training_hours : 0;
  if (h > maxHours) maxHours = h;
}
const maxHourClinics = candidateClinics.filter(c => (c.total_training_hours || 0) === maxHours);
let minPriceAmongMax = Infinity;
for (const c of maxHourClinics) {
  if (typeof c.price === 'number' && c.price < minPriceAmongMax) minPriceAmongMax = c.price;
}
const bestClinicIds = maxHourClinics.filter(c => c.price === minPriceAmongMax).map(c => c.id);

const candidateClinicIds = candidateClinics.map(c => c.id);

const regsForCandidates = regs.filter(r => candidateClinicIds.includes(r.clinic_id));
const regsForBest = regs.filter(r => bestClinicIds.includes(r.clinic_id));

// CP1 (0.5): Registered for any July 2026 pitching clinic under $120
checkpoints.push({ passed: regsForCandidates.length > 0, weight: 0.5 });

// CP2 (0.5): Registered for the best (max hours, then lowest price) clinic among those
checkpoints.push({ passed: regsForBest.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('field_reservation_slots') || '[]');
const reservations = JSON.parse(localStorage.getItem('field_reservations') || '[]');
const fields = JSON.parse(localStorage.getItem('fields') || '[]');
const divisions = JSON.parse(localStorage.getItem('divisions') || '[]');

const div12 = divisions.find(d => d.code === '12u');
if (!div12) {
  return 0.0;
}

const parseTimeToMinutes = (timeStr) => {
  if (!timeStr) return null;
  const match = timeStr.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (!match) return null;
  let h = parseInt(match[1], 10);
  const m = parseInt(match[2], 10);
  const ampm = match[3].toUpperCase();
  if (ampm === 'PM' && h !== 12) h += 12;
  if (ampm === 'AM' && h === 12) h = 0;
  return h * 60 + m;
};

// Eligible slots: 12U division, Wednesday, 1 hour, between 18:00 and 20:00, field has lights
const candidateSlots = slots.filter(s => {
  const field = fields.find(f => f.id === s.field_id);
  if (!field || !field.has_lights) return false;
  if (!s.date) return false;
  const dateStr = s.date.slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  const day = d.getUTCDay(); // 3 = Wednesday
  if (day !== 3) return false;
  if (s.division_id && s.division_id !== div12.id) return false;

  const startMin = parseTimeToMinutes(s.start_time);
  const endMin = parseTimeToMinutes(s.end_time);
  if (startMin == null || endMin == null) return false;
  const duration = endMin - startMin;
  if (duration !== 60) return false;
  if (startMin < 18 * 60 || startMin > 20 * 60) return false;
  return true;
});

if (candidateSlots.length === 0) {
  return 0.0;
}

// Find earliest by date then time; break ties by keeping first encountered
let bestSlot = null;
for (const s of candidateSlots) {
  if (!bestSlot) {
    bestSlot = s;
    continue;
  }
  const dateA = (s.date || '').slice(0, 10);
  const dateB = (bestSlot.date || '').slice(0, 10);
  if (dateA < dateB) {
    bestSlot = s;
    continue;
  } else if (dateA > dateB) {
    continue;
  }
  const startA = parseTimeToMinutes(s.start_time) || 0;
  const startB = parseTimeToMinutes(bestSlot.start_time) || 0;
  if (startA < startB) {
    bestSlot = s;
  }
}

const bestSlotId = bestSlot ? bestSlot.id : null;
const candidateSlotIds = candidateSlots.map(s => s.id);

// New reservations created at runtime have ids like 'field_res_###'
const dynamicReservations = reservations.filter(r => /^field_res_\d+/.test(r.id || '') && r.status === 'confirmed');

const eligibleReservations = dynamicReservations.filter(r => candidateSlotIds.includes(r.reservation_slot_id));
const bestReservations = eligibleReservations.filter(r => r.reservation_slot_id === bestSlotId);

// CP1 (0.5): Reserved any qualifying 12U Wednesday 6–8 PM lit-field one-hour slot
checkpoints.push({ passed: eligibleReservations.length > 0, weight: 0.5 });

// CP2 (0.5): Reserved the earliest such slot
checkpoints.push({ passed: !!bestSlotId && bestReservations.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const savedTeams = JSON.parse(localStorage.getItem('saved_teams') || '[]');
const teams = JSON.parse(localStorage.getItem('teams') || '[]');
const divisions = JSON.parse(localStorage.getItem('divisions') || '[]');
const practices = JSON.parse(localStorage.getItem('team_practices') || '[]');

const div10 = divisions.find(d => d.code === '10u');
if (!div10) {
  return 0.0;
}

const parseTimeToMinutes = (timeStr) => {
  if (!timeStr) return null;
  const match = timeStr.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (!match) return null;
  let h = parseInt(match[1], 10);
  const m = parseInt(match[2], 10);
  const ampm = match[3].toUpperCase();
  if (ampm === 'PM' && h !== 12) h += 12;
  if (ampm === 'AM' && h === 12) h = 0;
  return h * 60 + m;
};

const approxDistanceMiles = (zipA, zipB) => {
  if (!zipA || !zipB) return null;
  if (zipA === zipB) return 0;
  return 999;
};

// Candidate teams: 10U, beginner, within 10 miles, practices Tue/Thu afternoon or evening
const candidateTeams = [];
const earliestStartByTeam = {};

for (const t of teams) {
  if (t.division_id !== div10.id) continue;
  if (t.skill_level !== 'beginner') continue;
  const dist = approxDistanceMiles('12345', t.zip_code);
  if (dist === null || dist > 10) continue;

  const tPractices = practices.filter(p => p.team_id === t.id && (p.day_of_week === 'tuesday' || p.day_of_week === 'thursday'));
  if (tPractices.length === 0) continue;

  let earliest = Infinity;
  for (const p of tPractices) {
    const m = parseTimeToMinutes(p.start_time);
    if (m == null || m < 12 * 60) continue; // afternoon or evening
    if (m < earliest) earliest = m;
  }
  if (!isFinite(earliest)) continue;

  candidateTeams.push(t);
  earliestStartByTeam[t.id] = earliest;
}

if (candidateTeams.length === 0) {
  return 0.0;
}

let bestEarliest = Infinity;
for (const t of candidateTeams) {
  const m = earliestStartByTeam[t.id];
  if (m < bestEarliest) bestEarliest = m;
}
const bestTeamIds = candidateTeams.filter(t => earliestStartByTeam[t.id] === bestEarliest).map(t => t.id);

const candidateSaved = savedTeams.filter(st => candidateTeams.some(t => t.id === st.team_id));
const bestSaved = savedTeams.filter(st => bestTeamIds.includes(st.team_id));

// CP1 (0.5): Saved any team that meets all filters (10U, beginner, within 10 miles, Tue/Thu afternoon/evening practices)
checkpoints.push({ passed: candidateSaved.length > 0, weight: 0.5 });

// CP2 (0.5): Saved the team whose Tue/Thu practice starts earliest
checkpoints.push({ passed: bestSaved.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const savedResources = JSON.parse(localStorage.getItem('saved_resources') || '[]');
const docs = JSON.parse(localStorage.getItem('rule_documents') || '[]');

const batDocIds = docs
  .filter(d => d.division_code === '12u' && d.category === 'bat_regulations')
  .map(d => d.id);

const conductDocIds = docs
  .filter(d => d.division_code === 'all' && d.category === 'code_of_conduct')
  .map(d => d.id);

const hasBat = savedResources.some(sr => batDocIds.includes(sr.rule_document_id));
const hasConduct = savedResources.some(sr => conductDocIds.includes(sr.rule_document_id));

// CP1 (0.5): 12U bat regulations document saved
checkpoints.push({ passed: hasBat, weight: 0.5 });

// CP2 (0.5): League-wide Code of Conduct document saved
checkpoints.push({ passed: hasConduct, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
